// AUTO-GENERATED runner — do not import this file directly.
// Run: node scripts/sync-snippets.js
const fs = require('fs');
const path = require('path');

const manifest = require('./snippet-manifest');

const SNIPPETS_DIR = path.join(__dirname, '..', 'snippets');
const OUTPUT_FILE = path.join(__dirname, '..', 'client', 'src', 'config', 'snippets.generated.js');

function fileKey(filename) {
  if (filename === 'README.md') return 'readme';
  if (filename === 'package.json') return 'packageJson';
  // frontend.jsx → frontend, index.html → html, backend.js → backend
  const base = path.basename(filename, path.extname(filename));
  return base === 'index' ? 'html' : base;
}

function readSnippet(sourceDir, filename) {
  const filePath = path.join(sourceDir, filename);
  let content = fs.readFileSync(filePath, 'utf8');
  // Strip runtime env prefixes so CODE display shows clean placeholders
  content = content.replace(/window\._STRIPE_PK \|\| /g, '');
  content = content.replace(/process\.env\.STRIPE_SECRET_KEY \|\| /g, '');
  content = content.replace(/process\.env\.PORT \|\| /g, '');
  return content;
}

function escapeTemplateLiteral(str) {
  // Escape backticks and ${...} so content is safe inside a template literal
  return str.replace(/\\/g, '\\\\').replace(/`/g, '\\`').replace(/\$\{/g, '\\${');
}

let output = `// AUTO-GENERATED — run: node scripts/sync-snippets.js
// Do not edit this file directly. Edit files in snippets/ or the integration's app/ directory instead.
export const snippets = {\n`;

for (const [integration, variants] of Object.entries(manifest)) {
  output += `  '${integration}': {\n`;
  for (const [variant, entry] of Object.entries(variants)) {
    const isCustomDir = !Array.isArray(entry);
    const files = isCustomDir ? entry.files : entry;
    const sourceDir = isCustomDir
      ? path.join(__dirname, '..', entry.dir)
      : path.join(SNIPPETS_DIR, integration, variant);

    output += `    '${variant}': {\n`;
    for (const filename of files) {
      const key = fileKey(filename);
      const content = readSnippet(sourceDir, filename);
      output += `      ${key}: \`${escapeTemplateLiteral(content)}\`,\n`;
    }
    output += `    },\n`;
  }
  output += `  },\n`;
}

output += `};\n`;

fs.mkdirSync(path.dirname(OUTPUT_FILE), { recursive: true });
fs.writeFileSync(OUTPUT_FILE, output, 'utf8');
console.log('✓ snippets.generated.js written to', OUTPUT_FILE);
